INSERT INTO resenha_diaria (tipo_ato, numero_ato, ementa, url, data_publicacao, data_dou)
VALUES
('Lei', 'Lei nº 15.374, de 2.4.2026', 'Cria cargos efetivos, cargos em comissão e funções comissionadas no quadro de pessoal do Tribunal Superior Eleitoral e dos Tribunais Regionais Eleitorais.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15374.htm', '2 de abril de 2026', '2026-04-02'),
('Lei', 'Lei nº 15.373, de 1º.4.2026', 'Estabelece o reajuste dos vencimentos básicos dos cargos efetivos, dos cargos em comissão e das funções comissionadas dos servidores do Ministério Público da União e do Conselho Nacional do Ministério Público.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15373.htm', '2 de abril de 2026', '2026-04-02'),
('Lei', 'Lei nº 15.372, de 1º.4.2026', 'Altera a Lei nº 14.377, de 22 de junho de 2022, que dispõe sobre a estruturação do Plano de Carreiras e Cargos de Provimento Efetivo dos Servidores da Defensoria Pública da União; e fixa o valor de suas remunerações.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15372.htm', '2 de abril de 2026', '2026-04-02'),
('Decreto', 'Decreto nº 12.918, de 31.3.2026', 'Altera o Decreto nº 12.043, de 5 de junho de 2024, que cria a Assessoria Extraordinária para a COP30.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12918.htm', '1º de abril de 2026', '2026-04-01'),
('Lei', 'Lei nº 15.371, de 31.3.2026', 'Dispõe sobre a licença-paternidade; institui o salário-paternidade no âmbito da Previdência Social; e altera a Consolidação das Leis do Trabalho.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15371.htm', '1º de abril de 2026', '2026-04-01'),
('Lei', 'Lei nº 15.370, de 31.3.2026', 'Institui o Selo de Engenharia ou Arquitetura Solidária.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15370.htm', '1º de abril de 2026', '2026-04-01'),
('Lei', 'Lei nº 15.369, de 31.3.2026', 'Altera a Lei nº 9.394, de 20 de dezembro de 1996 (Lei de Diretrizes e Bases da Educação Nacional), para definir a extensão da oferta de educação infantil em creches e pré-escolas pelos Municípios às zonas urbanas e rurais.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15369.htm', '1º de abril de 2026', '2026-04-01'),
('Decreto', 'Decreto nº 12.917, de 31.3.2026', 'Altera o Decreto nº 5.493, de 18 de julho de 2005, que regulamenta o Programa Universidade para Todos.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12917.htm', '1º de abril de 2026', '2026-04-01')
